using UnityEngine;public class Operator : MonoBehaviour{    private readonly float CameraOffsetY = 3f;    private readonly float CameraOffsetZ = -5f;    [SerializeField] private Transform _ball;    private Camera _camera;    private void Awake()    {        _camera = Camera.main;    }    private void LateUpdate()    {        _camera.transform.position = new Vector3(_ball.position.x, _ball.position.y + CameraOffsetY, _ball.position.z + CameraOffsetZ);    }}